const crypto = require('crypto');
const competitor = $('SplitInBatches').item.json;
const response = $input.first().json;

if (competitor.status && competitor.status.toLowerCase() === 'inactive') {
  return [{json: {
    competitor_name: competitor.competitor_name,
    url: competitor.url,
    section_to_monitor: competitor.section_to_monitor || '',
    last_content: competitor.last_content || '',
    last_checked: competitor.last_checked || '',
    status: 'skip_inactive',
    newContent: '',
    newHash: '',
    fetchedAt: new Date().toISOString()
  }}];
}

const rawHtml = response.data || response.body || String(response) || '';

if (!rawHtml || rawHtml.length < 50) {
  return [{json: {
    competitor_name: competitor.competitor_name,
    url: competitor.url,
    section_to_monitor: competitor.section_to_monitor || '',
    last_content: competitor.last_content || '',
    last_checked: competitor.last_checked || '',
    status: 'fetch_error',
    newContent: '',
    newHash: 'error_' + Date.now(),
    fetchedAt: new Date().toISOString(),
    error: 'Respuesta vacía o error de red'
  }}];
}

const priceMatches = (rawHtml.match(/\$[\s]?[\d.,]+/g) || []).slice(0, 10);
const titleMatches = (rawHtml.match(/<h[1-3][^>]*>([^<]+)<\/h[1-3]>/gi) || [])
  .map(h => h.replace(/<[^>]+>/g, '').trim())
  .filter(t => t.length > 2)
  .slice(0, 5);

let text = rawHtml
  .replace(/<script[\s\S]*?<\/script>/gi, '')
  .replace(/<style[\s\S]*?<\/style>/gi, '')
  .replace(/<nav[\s\S]*?<\/nav>/gi, '')
  .replace(/<footer[\s\S]*?<\/footer>/gi, '')
  .replace(/<header[\s\S]*?<\/header>/gi, '')
  .replace(/<!--[\s\S]*?-->/g, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/&nbsp;/g, ' ')
  .replace(/&amp;/g, '&')
  .replace(/&lt;/g, '<')
  .replace(/&gt;/g, '>')
  .replace(/\s+/g, ' ')
  .trim()
  .substring(0, 3000);

const hash = crypto.createHash('md5').update(text).digest('hex');

return [{json: {
  competitor_name: competitor.competitor_name,
  url: competitor.url,
  section_to_monitor: competitor.section_to_monitor || '',
  last_content: competitor.last_content || '',
  last_checked: competitor.last_checked || '',
  status: 'ok',
  newContent: text,
  newHash: hash,
  extractedPrices: priceMatches,
  extractedTitles: titleMatches,
  fetchedAt: new Date().toISOString()
}}];

const data = $input.first().json;

if (data.status === 'fetch_error' || data.status === 'skip_inactive') {
  return [{json: { ...data, skipComparison: true }}];
}

if (!data.last_content || data.last_content.trim() === '') {
  return [{json: { ...data, skipComparison: false, isFirstRun: true }}];
}

return [{json: { ...data, skipComparison: false, isFirstRun: false }}];

const crypto = require('crypto');
const data = $input.first().json;

if (data.skipComparison) {
  return [{json: { ...data, status: 'no_change', comparisonStatus: 'skip', diff: null }}];
}

if (data.isFirstRun) {
  return [{json: {
    ...data,
    status: 'no_change',
    comparisonStatus: 'baseline',
    diff: null,
    note: 'Primera ejecución — línea base establecida'
  }}];
}

const oldHash = crypto.createHash('md5').update(data.last_content).digest('hex');

if (oldHash === data.newHash) {
  return [{json: { ...data, status: 'no_change', comparisonStatus: 'identical', diff: null }}];
}

const oldSnippet = data.last_content.substring(0, 800);
const newSnippet = data.newContent.substring(0, 800);

const oldWordSet = new Set(data.last_content.split(/\s+/).filter(w => w.length > 4));
const newWords = data.newContent.split(/\s+/).filter(w => w.length > 4);
const addedTerms = [...new Set(newWords.filter(w => !oldWordSet.has(w)))].slice(0, 30);

const diff = `CONTENIDO ANTERIOR (primeros 800 chars):\n${oldSnippet}\n\nCONTENIDO ACTUAL (primeros 800 chars):\n${newSnippet}\n\nTÉRMINOS NUEVOS DETECTADOS: ${addedTerms.join(', ') || 'ninguno'}\nPRECIOS VISIBLES: ${(data.extractedPrices || []).join(', ') || 'ninguno'}\nTÍTULOS: ${(data.extractedTitles || []).join(' | ') || 'ninguno'}`;

return [{json: {
  ...data,
  status: 'changed',
  comparisonStatus: 'changed',
  diff,
  changedAt: new Date().toISOString()
}}];

